        $lorem = 'বাংলাদেশের সংবাদ মাধ্যমে আজকের এই খবরটি বিশেষ গুরুত্বের সাথে প্রচারিত হয়েছে। দেশের বিভিন্ন প্রান্ত থেকে প্রতিনিধিরা এই ঘটনার বিস্তারিত তথ্য সংগ্রহ করেছেন। বিশেষজ্ঞরা জানিয়েছেন যে এই ঘটনাটি আগামী দিনগুলোতে দেশের সামগ্রিক পরিস্থিতিতে উল্লেখযোগ্য প্রভাব ফেলবে। সংশ্লিষ্ট কর্তৃপক্ষ বিষয়টিকে গুরুত্বের সাথে বিবেচনা করছে এবং দ্রুত কার্যকর পদক্ষেপ নেওয়ার আশ্বাস দিয়েছে। দেশের সাধারণ মানুষ এই বিষয়ে গভীর আগ্রহ দেখাচ্ছেন এবং সামাজিক মাধ্যমে ব্যাপক আলোচনা চলছে। আগামী দিনে এই বিষয়ে আরও বিস্তারিত তথ্য জানা যাবে বলে সূত্র জানিয়েছে।';

        $categories = Category::all()->keyBy('slug');
        $users = User::all();
        $statuses = ['published', 'published', 'published', 'draft', 'scheduled'];
        $newsCount = 0;

        foreach ($newsTemplates as $slug => $articles) {
            $category = $categories->get($slug);
            if (!$category) continue;

            foreach ($articles as $i => $article) {
                $titleBase = $article['title'];
                $uniqueTitle = $titleBase;
                $counter = 1;
                while (News::where('title', $uniqueTitle)->exists()) {
                    $uniqueTitle = $titleBase . ' (' . $counter . ')';
                    $counter++;
                }

                $status = 'published';
                if ($i === 3) $status = 'draft';
                if ($i === 4) $status = 'scheduled';

                News::create([
                    'title'        => $uniqueTitle,
                    'slug'         => Str::slug($uniqueTitle) . '-' . uniqid(),
                    'category_id'  => $category->id,
                    'author_id'    => $users->random()->id,
                    'content'      => '<p>' . implode('</p><p>', array_fill(0, 4, $lorem)) . '</p>',
                    'excerpt'      => $article['excerpt'],
                    'status'       => $status,
                    'is_featured'  => $i === 0,
                    'is_breaking'  => $i === 1,
                    'views'        => rand(100, 15000),
                    'published_at' => $status === 'published' ? now()->subDays(rand(0, 30)) : ($status === 'scheduled' ? now()->addDays(rand(1, 7)) : null),
                ]);
                $newsCount++;
            }
        }

        $this->command->info("✅ {$newsCount} টি নিউজ সফলভাবে তৈরি হয়েছে!");
